n        self.blob_store\n            .write(content)\n            .unwrap_or_else(|err| format!(\"error:{err}\"))\n    }\n}\n\npub fn json_value_to_vec(value: &Value) -> Vec<u8> {\n    serde_json::to_vec(value).unwrap_or_default()\n}\n","exit_code":0,"status":"completed"}}
